package com.example.grpc;

import io.grpc.stub.StreamObserver;
import io.grpc.ServerServiceDefinition;
import io.grpc.BindableService;
import java.io.IOException;

public class FileUploadService extends BindableService {
    private static final Logger logger = LogManager.getLogger(FileUploadService.class);

    @Override
    public ServerServiceDefinition bindService() {
        return ServerServiceDefinition.builder("FileUpload")
                .addMethod(this::upload)
                .build();
    }

    private void upload(InputStream inputStream, OutputStream outputStream, StreamObserver<Object> observer) {
        try {
            int read;
            byte[] buffer = new byte[1024];
            while ((read = inputStream.read(buffer)) > 0) {
                outputStream.write(buffer, 0, read);
                observer.onNext(new Object());
            }
        } catch (IOException e) {
            observer.onError(e);
        } finally {
            observer.onCompleted();
        }
    }
}